import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface FunnelStage {
  stage: string;
  current: number;
  previous: number;
  conversionRate: number;
}

interface ConversionFunnelData {
  funnel: FunnelStage[];
}

export default function Widget() {
  const data = response.data as ConversionFunnelData;
  const clipPathId = useId();

  const stages = data.funnel.map((f) => f.stage);
  const currentValues = data.funnel.map((f) => f.current);
  const conversionRates = data.funnel.map((f) => f.conversionRate);

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1E1E1E', color: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#FF5722' }}>
              Conversion Funnel
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 250 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: currentValues,
                  color: '#FFC107',
                  label: 'Current',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: stages,
                  id: 'stages',
                },
              ]}
              yAxis={[{ id: 'values' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="stages"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsYAxis
                axisId="values"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>

          <Stack direction="row" spacing={0.5} justifyContent="space-between">
            {data.funnel.map((funnelStage) => (
              <Box key={funnelStage.stage} textAlign="center">
                <Typography variant="caption" color="text.secondary">
                  {funnelStage.stage}
                </Typography>
                <Typography variant="body2" fontWeight={500} sx={{ color: '#FFC107' }}>
                  {funnelStage.conversionRate}%
                </Typography>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
